'use strict';
const APP_NAME='Second Brain OS';
const BUILD='second-brain-space-v20-20260701';
const STORE_KEY='secondBrainOS.v1';
const $=s=>document.querySelector(s);
const $$=s=>Array.from(document.querySelectorAll(s));
const uid=()=>Math.random().toString(36).slice(2,9)+Date.now().toString(36).slice(-4);
const today=()=>new Date().toISOString().slice(0,10);
const month=()=>today().slice(0,7);
const esc=v=>String(v??'').replace(/[&<>"']/g,ch=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[ch]));
const num=v=>Number(String(v??'').replace(/\s/g,'').replace(',','.'))||0;
const money=v=>`${Math.round(num(v)).toLocaleString('ru-RU')} ₽`;
const clamp=(v,a=0,b=100)=>Math.max(a,Math.min(b,Number(v)||0));
const addDays=(d,n)=>{const x=new Date(d);x.setDate(x.getDate()+n);return x};
const iso=d=>new Date(d).toISOString().slice(0,10);
const fmt=d=>d?new Date(d).toLocaleDateString('ru-RU',{day:'numeric',month:'short',year:'numeric'}):'без даты';
const shortFmt=d=>d?new Date(d).toLocaleDateString('ru-RU',{day:'numeric',month:'short'}):'—';
let page=location.hash?location.hash.slice(1):'dashboard';
let state=normalize(load());

document.title=APP_NAME;
try{localStorage.setItem('secondBrainOS.currentBuild',BUILD);const m=document.querySelector('meta[name="second-brain-build"]');if(m)m.content=BUILD;}catch(e){}

